import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine(); // Use nextLine() to read a whole line

        if (input.length() > 10) {
            System.out.println("Input string is too long. Exiting...");
            return;
        }

        char[] buffer = new char[10];
        input.getChars(0, Math.min(input.length(), buffer.length), buffer, 0); // Copy up to buffer length

        System.out.println("Buffer overflow avoided");
    }
}

### Explanation:
취약유형: Buffer Overflow
